using namespace std;
namespace phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
	}
}
using namespace phigrOS;
int n,a[25][25];
int f[(1<<20)+1][21];
signed main()
{
	n=read();
	FOR(i,1,n)
	{
		FOR(j,1,n)
		{
			a[i][j]=read();
		}
	}
	cli(f);
	f[1][1]=0;
	FOR(i,2,(1<<n)-1)
	{
		FOR(j,1,n)
		{
			if(!(i&(1<<(j-1))))
				continue;
			FOR(k,1,n)
			{
				if(k==j||!(i&(1<<(k-1))))
					continue;
				f[i][j]=min(f[i][j],f[i-(1<<(j-1))][k]+a[k][j]);
			}
		}
	}
	int ans=llinf;
	FOR(i,1,n)
	{
		ans=min(ans,f[(1<<n)-1][i]+a[i][1]);
	}
	writeln(ans);
	return 0;
}
